import React from "react";
import styles from "./popular.module.css";
import Title from "../../title";
import ProductData from "../../nav-list/nav-list.json";
import ProductCard from "../../product-card";

interface ProductDataProps {
  id: number;
  name: string;
  price: number;
  img: string;
}

const Popular: React.FC<ProductDataProps> = () => {
  const topCards = ProductData.ProductData.slice(0, 4);
  return (
    <div className={styles.popular}>
      <div className="container">
        <div className={styles.container_inner}>
          <Title level="h2" className={styles.title}>
            Popular
          </Title>
          <Title level="h5" className={styles.subtitle}>
            Our top-selling products that you may like
          </Title>
          <div className={styles.wrapper_cards}>
            {topCards.map(({ id, product }) => (
              <div key={id}>
                <ProductCard href={`/product/${product.id}`} imgSrc={product.img} name={name} price={price} />
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Popular;
